        private static BsonDocument BuildEmbeddedMovie(
            string title, string fullplot, int runtime, int year, float[] embedding) =>
            new BsonDocument
            {
                { "title", title },
                { "fullplot", fullplot },
                { "runtime", runtime },
                { "year", year },
                { "plot_embedding", new BinaryVectorFloat32(embedding).ToBsonBinaryData() }
            };
    }
